def add_tax(amount, rate):
    return round(amount + amount * rate, 2)


def format_price(amount):
    return '${:.2f}'.format(amount)

from money import add_tax, format_price


def cart_total(prices, tax_rate):
    subtotal = sum(prices)
    return format_price(add_tax(subtotal, tax_rate))
